import{_ as d,c as a,o as i,aj as l}from"./chunks/framework.CynFBi0q.js";const b=JSON.parse('{"title":"第10章 能力迁移：电商类产品设计","description":"","frontmatter":{},"headers":[],"relativePath":"handbook/ai-product/chapter_10.md","filePath":"handbook/ai-product/chapter_10.md","lastUpdated":1782008855000}'),r={name:"handbook/ai-product/chapter_10.md"};function s(p,t,n,e,o,u){return i(),a("div",null,[...t[0]||(t[0]=[l(`<h1 id="第10章-能力迁移-电商类产品设计" tabindex="-1">第10章 能力迁移：电商类产品设计 <a class="header-anchor" href="#第10章-能力迁移-电商类产品设计" aria-label="Permalink to “第10章 能力迁移：电商类产品设计”">​</a></h1><p>电商是互联网最大的赛道之一。2023年中国电商交易规模超过43万亿元。一个电商产品经理，需要理解商品体系、交易流程、营销体系这三大核心模块。</p><p>我是怕浪猫，这一章帮你从零搭建电商产品的骨架。</p><h2 id="_10-1-电商产品基础" tabindex="-1">10.1 电商产品基础 <a class="header-anchor" href="#_10-1-电商产品基础" aria-label="Permalink to “10.1 电商产品基础”">​</a></h2><h3 id="_10-1-1-电商产品核心概念-spu-sku-类目" tabindex="-1">10.1.1 电商产品核心概念（SPU/SKU/类目） <a class="header-anchor" href="#_10-1-1-电商产品核心概念-spu-sku-类目" aria-label="Permalink to “10.1.1 电商产品核心概念（SPU/SKU/类目）”">​</a></h3><p><strong>SPU与SKU</strong></p><p>SPU（Standard Product Unit）：标准化产品单元。iPhone 15是一个SPU。</p><p>SKU（Stock Keeping Unit）：库存量单位。iPhone 15 256G 黑色是一个SKU。</p><p>关系：一个SPU包含多个SKU。iPhone 15这个SPU，包含&quot;256G黑色&quot;、&quot;256G白色&quot;、&quot;512G黑色&quot;等多个SKU。</p><p><strong>类目体系</strong></p><p>电商类目是树状结构：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>一级类目：手机</span></span>
<span class="line"><span>  二级类目：智能手机</span></span>
<span class="line"><span>    三级类目：iPhone</span></span>
<span class="line"><span>      品牌：Apple</span></span>
<span class="line"><span>        系列：iPhone 15</span></span>
<span class="line"><span>          SPU：iPhone 15</span></span>
<span class="line"><span>            SKU：iPhone 15 256G 黑色</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p><strong>商品与订单的关系</strong></p><p>商品（SPU/SKU）→ 加入购物车 → 生成订单 → 支付 → 发货 → 确认收货 → 完成</p><p>每一个环节都是产品经理要设计的功能点。</p><p><strong>电商商品搜索设计</strong></p><p>搜索是电商用户找商品的第一入口，超过60%的电商用户直接通过搜索到达商品。搜索设计不好，用户连商品都找不到，后续所有流程都是零。</p><p>搜索框交互设计：</p><p>搜索框是用户与搜索系统交互的第一个触点。好的搜索框要降低用户的输入成本，提高意图识别的准确度。</p><ul><li>搜索框位置：首页顶部固定，输入框宽度至少占屏幕60%，确保用户一眼就能找到。</li><li>默认提示词（Placeholder）：根据用户画像动态展示，如&quot;限时特惠 手机&quot;&quot;热卖 运动鞋&quot;，既提示搜索功能又引导消费。</li><li>搜索框聚焦行为：聚焦后自动展示&quot;搜索发现&quot;模块，展示平台热搜词、用户历史搜索、猜你想搜，降低输入成本。</li><li>语音搜索与图片搜索：移动端提供语音输入入口，部分品类（服装、家居）提供拍照搜图功能，覆盖不方便打字的场景。</li><li>搜索框清空按钮：输入内容后右侧展示&quot;X&quot;清空按钮，一键清除重新输入。</li></ul><p>搜索建议设计：</p><p>用户开始输入时，实时返回搜索建议（Suggestion），帮助用户快速到达目标。</p><table tabindex="0"><thead><tr><th>搜索建议类型</th><th>触发时机</th><th>内容来源</th><th>展示优先级</th></tr></thead><tbody><tr><td>历史搜索</td><td>聚焦即展示</td><td>用户本地历史</td><td>1（最高）</td></tr><tr><td>热搜词</td><td>聚焦即展示</td><td>平台实时热词</td><td>2</td></tr><tr><td>联想词</td><td>输入1个字起</td><td>搜索日志+类目词库</td><td>3</td></tr><tr><td>品牌直达</td><td>输入品牌名</td><td>品牌库匹配</td><td>4</td></tr><tr><td>商品直达</td><td>输入精准词</td><td>SKU名称匹配</td><td>5</td></tr></tbody></table><p>搜索建议的交互细节：</p><ul><li>输入延迟：用户停止输入300ms后发起请求，避免频繁请求浪费资源。</li><li>高亮匹配：联想词中匹配用户输入的部分用加粗或颜色高亮，帮助用户快速定位。</li><li>分类标签：联想词右侧展示所属分类标签（如&quot;手机&quot;&quot;服饰&quot;），帮助用户判断意图方向。</li><li>请求缓存：相同输入结果的本地缓存，重复输入直接展示，减少网络请求。</li><li>最大展示条数：联想词最多展示10条，历史搜索最多展示15条，避免信息过载。</li></ul><p>搜索结果排序设计：</p><p>搜索结果页是用户决策的关键页面。排序逻辑直接决定用户能否找到想要的商品。</p><p>排序策略采用多因子加权模型：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>综合排序分 = 文本相关性 × 0.3 + 销量因子 × 0.25 + 转化率因子 × 0.2 + </span></span>
<span class="line"><span>            时效性因子 × 0.1 + 商品质量分 × 0.1 + 商家服务分 × 0.05</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>用户可切换的排序维度：</p><table tabindex="0"><thead><tr><th>排序方式</th><th>排序逻辑</th><th>适用场景</th></tr></thead><tbody><tr><td>综合排序</td><td>多因子加权</td><td>默认排序，全场景适用</td></tr><tr><td>销量排序</td><td>按近30天销量降序</td><td>用户想买大众款时</td></tr><tr><td>价格升序</td><td>按SKU最低价升序</td><td>用户追求低价时</td></tr><tr><td>价格降序</td><td>按SKU最低价降序</td><td>用户追求品质时</td></tr><tr><td>好评排序</td><td>按好评率降序</td><td>用户看重口碑时</td></tr><tr><td>上新排序</td><td>按发布时间降序</td><td>用户追新款时</td></tr></tbody></table><p><strong>商品筛选器设计</strong></p><p>搜索结果通常有几百上千条，筛选器帮助用户快速缩小范围。</p><p>筛选器的核心设计原则：常用筛选项前置，不常用的折叠或收起。</p><p>筛选器页面结构：</p><ul><li>顶部快捷筛选栏：价格区间、品牌、发货地。这三个是电商最常用的筛选维度，直接露出。</li><li>展开筛选面板：点击&quot;筛选&quot;按钮后展开完整面板，包含分类、规格、服务保障等全部筛选维度。</li><li>已选条件标签：选中的筛选条件在搜索框下方展示为标签，支持单个删除和一键清空。</li><li>筛选结果计数：每选一个筛选条件，实时更新结果数量，让用户知道当前筛选范围有多少商品。</li></ul><table tabindex="0"><thead><tr><th>筛选维度</th><th>筛选方式</th><th>设计要点</th></tr></thead><tbody><tr><td>价格区间</td><td>滑块+输入框</td><td>预设常用区间（0-50、50-100等），同时支持自定义输入</td></tr><tr><td>品牌</td><td>多选+搜索</td><td>品牌多时提供搜索框，支持拼音首字母索引</td></tr><tr><td>规格属性</td><td>多选</td><td>根据类目动态展示，手机类目展示内存/颜色，服装展示尺码/颜色</td></tr><tr><td>服务保障</td><td>多选</td><td>&quot;包邮&quot;&quot;7天无理由&quot;&quot;假一赔十&quot;等标签式筛选</td></tr><tr><td>发货地</td><td>单选</td><td>展示商品数量Top10的省份，其余折叠</td></tr><tr><td>店铺类型</td><td>单选</td><td>&quot;旗舰店&quot;&quot;专营店&quot;&quot;普通店铺&quot;</td></tr></tbody></table><p>筛选器的交互细节：</p><ul><li>筛选条件之间默认取交集（AND逻辑），同类目内多个值取并集（OR逻辑）。选了&quot;红色&quot;和&quot;蓝色&quot;，结果是红色或蓝色的商品。</li><li>筛选结果为空时，提示&quot;暂无符合条件的商品&quot;，并推荐放宽筛选条件。</li><li>筛选条件变化后自动刷新结果，不需要用户点&quot;确定&quot;按钮，减少操作步骤。</li></ul><h3 id="_10-1-2-商品体系设计" tabindex="-1">10.1.2 商品体系设计 <a class="header-anchor" href="#_10-1-2-商品体系设计" aria-label="Permalink to “10.1.2 商品体系设计”">​</a></h3><p><strong>商品信息结构</strong></p><table tabindex="0"><thead><tr><th>层级</th><th>包含信息</th><th>说明</th></tr></thead><tbody><tr><td>SPU层</td><td>商品名称、品牌、系列、基础描述</td><td>所有SKU共享的信息</td></tr><tr><td>SKU层</td><td>规格（颜色/尺寸/容量）、价格、库存</td><td>每个SKU独有的信息</td></tr><tr><td>销售层</td><td>销量、评价、售后服务</td><td>销售相关的信息</td></tr><tr><td>展示层</td><td>商品图片、详情页、视频</td><td>用户看到的信息</td></tr></tbody></table><p><strong>商品发布流程设计</strong></p><p>Step 1：选择类目。从一级类目逐级选择到三级类目。</p><p>Step 2：填写SPU信息。商品名称、品牌、基础描述。</p><p>Step 3：填写SKU信息。每个规格组合的价格、库存、编码。</p><p>Step 4：上传商品素材。主图、详情图、视频。</p><p>Step 5：设置销售信息。运费模板、售后服务、发票设置。</p><p>Step 6：提交审核。平台审核商品信息是否合规。</p><h3 id="_10-1-3-交易流程设计" tabindex="-1">10.1.3 交易流程设计 <a class="header-anchor" href="#_10-1-3-交易流程设计" aria-label="Permalink to “10.1.3 交易流程设计”">​</a></h3><p><strong>标准交易流程</strong></p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>浏览商品 → 选择规格 → 加入购物车 → 去结算 → 确认订单 → </span></span>
<span class="line"><span>选择地址 → 选择支付方式 → 确认支付 → 支付成功 → </span></span>
<span class="line"><span>生成订单 → 商家发货 → 物流配送 → 确认收货 → 评价 → 完成</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><strong>交易流程的关键决策点</strong></p><p>决策点一：购物车是必须的吗？</p><p>不是。抖音电商没有购物车，直接&quot;立即购买&quot;。适合冲动消费场景。</p><p>决策点二：是否需要支持&quot;多SKU合并支付&quot;？</p><p>适合购物车场景。用户选了多个SKU，可以合并生成一个订单，降低支付摩擦。</p><p>决策点三：是否需要支持&quot;货到付款&quot;？</p><p>适合下沉市场。用户不信任线上支付时，货到付款能提升转化率。</p><p><strong>购物车设计</strong></p><p>购物车是电商交易流程的核心枢纽。它不是简单的&quot;暂存区&quot;，而是一个影响客单价和转化率的关键功能。</p><p>购物车页面结构：</p><table tabindex="0"><thead><tr><th>区域</th><th>内容</th><th>设计目的</th></tr></thead><tbody><tr><td>店铺分组区</td><td>按店铺分组展示商品</td><td>方便跨店结算和店铺级优惠</td></tr><tr><td>商品信息区</td><td>商品图、名称、规格、单价</td><td>帮用户确认商品信息</td></tr><tr><td>数量修改区</td><td>加减按钮+数量输入</td><td>允许用户调整购买数量</td></tr><tr><td>优惠信息区</td><td>优惠券标签、满减提示</td><td>刺激用户凑单</td></tr><tr><td>结算栏</td><td>合计金额、优惠金额、结算按钮</td><td>一键进入结算流程</td></tr></tbody></table><p>商品数量修改设计：</p><ul><li>加减按钮：点击&quot;+&quot;增加1个，点击&quot;-&quot;减少1个，数量为1时&quot;-&quot;按钮置灰不可点。</li><li>直接输入：点击数量数字可切换为输入框，支持直接输入数量，输入后失焦即保存。</li><li>库存上限：数量不能超过该SKU可用库存，超过时自动调整为库存上限并弹出提示&quot;已达最大库存&quot;。</li><li>限购控制：如有&quot;每人限购X件&quot;规则，数量不能超过限购数，超限时提示&quot;该商品每人限购X件&quot;。</li><li>起售数量：部分商品（如批发类）有起售数量，低于起售数时无法减少。</li><li>数量变化后实时更新：小计金额、合计金额、优惠金额、满减进度均实时刷新，不需要用户手动刷新。</li></ul><p>优惠券选择设计：</p><p>优惠券选择是购物车里最影响用户体验的功能之一。选对了省钱，选错了用户觉得平台在骗人。</p><ul><li>自动推荐最优券：系统计算所有可用优惠券组合，自动选中优惠力度最大的方案。用户不需要自己算。</li><li>手动切换：用户点击优惠券区域可展开优惠券列表，手动选择其他券。列表中标注每张券的优惠金额和可用状态。</li><li>不可用券说明：不可用的券灰度展示，并说明原因（&quot;未达满减门槛，还差¥32&quot;&quot;该商品不参与此券活动&quot;等）。</li><li>店铺券与平台券叠加：同时支持店铺券和平台券时，展示&quot;店铺优惠&quot;和&quot;平台优惠&quot;两个分区，分别选择。</li><li>优惠金额预览：选中优惠券后，在合计栏实时展示&quot;已优惠¥XX&quot;，让用户清晰感知省了多少钱。</li></ul><p>结算流程设计：</p><ul><li>底部结算栏固定展示：合计金额、优惠金额、&quot;结算(X)&quot;按钮（X为已勾选商品件数），始终可见。</li><li>全选/反选：左上角全选复选框，支持一键全选和反选。</li><li>跨店结算：多店铺商品可勾选后合并结算，生成多个子订单（每店一个子订单），但对用户表现为一次支付。</li><li>失效商品处理：已下架或已售罄的商品灰度展示并标注&quot;已失效&quot;，不参与合计计算，提供&quot;删除失效商品&quot;快捷按钮。</li><li>凑单提示：当购物车内金额距下一个满减门槛差额较小时，展示&quot;再买¥XX可享满减优惠&quot;，引导凑单提升客单价。</li></ul><p><strong>退款流程设计</strong></p><p>退款是交易流程中用户情绪最敏感的环节。退款设计不好，用户不但退款，还永远不再来了。</p><p>退款类型与适用场景：</p><table tabindex="0"><thead><tr><th>退款类型</th><th>适用阶段</th><th>退款内容</th><th>是否需要退货</th></tr></thead><tbody><tr><td>仅退款</td><td>未发货</td><td>全额退款</td><td>否</td></tr><tr><td>仅退款</td><td>已签收-质量问题</td><td>退款+补偿</td><td>否</td></tr><tr><td>退货退款</td><td>已发货未签收</td><td>全额退款</td><td>是（拦截或拒收）</td></tr><tr><td>退货退款</td><td>已签收-7天无理由</td><td>全额退款</td><td>是</td></tr><tr><td>换货</td><td>已签收-质量问题</td><td>换同款或同价位</td><td>是（先寄回再寄出）</td></tr></tbody></table><p>退款流程状态机：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>[提交退款申请] → [商家审核] </span></span>
<span class="line"><span>    → 审核通过 → [等待退货](退货退款) → [用户寄回] → [商家确认收货] → [退款中] → [退款成功]</span></span>
<span class="line"><span>    → 审核通过 → [退款中](仅退款) → [退款成功]</span></span>
<span class="line"><span>    → 审核拒绝 → [退款关闭]（用户可申请平台介入）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>退款流程的关键设计点：</p><ul><li>退款原因选择：提供结构化的退款原因选项（&quot;不想要了&quot;&quot;商品质量问题&quot;&quot;发错货&quot;&quot;与描述不符&quot;等），不同原因对应不同的处理流程。</li><li>凭证上传：质量问题需要上传照片或视频凭证，最多9张图，单张不超过5MB。</li><li>退款金额计算：原价退款为默认，如有优惠券需根据分摊规则计算实际退款金额。用户使用了满减券，部分商品退款时需按比例扣除优惠。</li><li>退款时效承诺：页面展示&quot;商家将在48小时内审核&quot;，给用户明确的预期。</li><li>退款进度通知：每个状态变更都推送消息通知用户，包括商家审核结果、退货物流状态、退款到账通知。</li><li>极速退款：平台信用分高的用户可享&quot;极速退款&quot;——商家审核通过后平台先行垫付退款，无需等商家确认收货。</li></ul><h3 id="_10-1-4-营销体系设计" tabindex="-1">10.1.4 营销体系设计 <a class="header-anchor" href="#_10-1-4-营销体系设计" aria-label="Permalink to “10.1.4 营销体系设计”">​</a></h3><p><strong>营销工具矩阵</strong></p><table tabindex="0"><thead><tr><th>工具</th><th>核心逻辑</th><th>产品设计要点</th></tr></thead><tbody><tr><td>优惠券</td><td>满减/折扣</td><td>领取限制、使用门槛、有效期</td></tr><tr><td>秒杀</td><td>限时低价</td><td>库存控制、防刷机制</td></tr><tr><td>拼团</td><td>多人成团</td><td>成团规则、退款机制</td></tr><tr><td>砍价</td><td>邀请好友砍价</td><td>砍价幅度算法、防刷机制</td></tr><tr><td>分销</td><td>推广赚佣金</td><td>佣金比例、结算周期</td></tr></tbody></table><p><strong>优惠券系统设计</strong></p><p>优惠券系统包含三个核心模块：</p><p>模块一：优惠券创建。运营在后台创建优惠券，设置面额、门槛、库存、有效期。</p><p>模块二：优惠券发放。用户领取或系统自动发放。</p><p>模块三：优惠券使用。下单时选择可用优惠券，满足条件后抵扣。</p><p><strong>优惠券状态机</strong></p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>[未领取] --用户领取--&gt; [已领取] --下单使用--&gt; [已使用]</span></span>
<span class="line"><span>                         ↓ 过期</span></span>
<span class="line"><span>                     [已过期]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><strong>满减活动设计</strong></p><p>满减是电商最常用的促销工具之一。&quot;满200减20&quot;这种设计，本质是通过门槛设计刺激用户多买，提升客单价。</p><p>满减活动的核心参数：</p><table tabindex="0"><thead><tr><th>参数</th><th>说明</th><th>设计建议</th></tr></thead><tbody><tr><td>满减门槛</td><td>触发优惠的最低金额</td><td>设置在当前客单价1.3-1.5倍，让多数用户觉得&quot;再买一点就够了&quot;</td></tr><tr><td>优惠金额</td><td>门槛达成后减免的金额</td><td>优惠力度在5%-15%之间，太低没吸引力，太高伤利润</td></tr><tr><td>活动层级</td><td>是否支持多档满减</td><td>支持&quot;满100减10、满200减25、满300减40&quot;阶梯式设计</td></tr><tr><td>适用范围</td><td>全场/品类/指定商品</td><td>新手运营建议从品类级开始，避免全场满减导致利润失控</td></tr><tr><td>叠加规则</td><td>是否可与优惠券叠加</td><td>明确标注，&quot;与优惠券不可叠加&quot;或&quot;可叠加使用&quot;</td></tr><tr><td>活动时间</td><td>开始和结束时间</td><td>限时制造紧迫感，一般3-7天一个周期</td></tr></tbody></table><p>满减活动的前端展示设计：</p><ul><li>商品详情页：价格下方展示&quot;满200减20&quot;标签，点击可展开查看完整活动规则。</li><li>购物车页：底部结算栏上方展示&quot;再买¥XX可享满减&quot;进度条，实时计算差额。</li><li>凑单推荐：当购物车金额距满减门槛差额较小时，推荐&quot;再买这些可享满减&quot;的商品列表。</li><li>结算页：优惠明细中展示满减优惠金额，让用户确认优惠已生效。</li></ul><p>满减活动的防坑设计：</p><ul><li>虚假满减检测：系统自动检测是否存在&quot;先涨价再满减&quot;行为，满减后价格不得高于近30天最低价。</li><li>满减后退款处理：退货退款时按比例扣除满减优惠，不能让用户通过满减套利。</li><li>满减库存预算：设置满减活动的总优惠预算上限，超出后自动关闭活动或降档。</li></ul><p><strong>会员体系设计</strong></p><p>会员体系是电商用户留存的核心手段。好的会员体系让用户觉得&quot;越买越划算&quot;，形成复购习惯。</p><p>会员等级设计：</p><table tabindex="0"><thead><tr><th>会员等级</th><th>升级条件（近365天）</th><th>有效期</th><th>核心权益</th></tr></thead><tbody><tr><td>普通会员</td><td>注册即享</td><td>永久</td><td>基础服务</td></tr><tr><td>银卡会员</td><td>累计消费满500元</td><td>1年</td><td>9.8折、专属客服</td></tr><tr><td>金卡会员</td><td>累计消费满2000元</td><td>1年</td><td>9.5折、免运费、优先发货</td></tr><tr><td>钻石会员</td><td>累计消费满5000元</td><td>1年</td><td>9折、免运费、专属价、生日礼包</td></tr><tr><td>黑卡会员</td><td>累计消费满20000元</td><td>1年</td><td>8.5折、全场免运费、专属经理、新品优先</td></tr></tbody></table><p>会员等级的设计要点：</p><ul><li>升级条件用&quot;消费金额&quot;而非&quot;订单数量&quot;，避免用户拆单刷等级。</li><li>等级有效期1年，到期后根据近365天消费重新计算，保持用户的消费动力。</li><li>升级即时生效，降级在到期后生效，给用户一个月的保级缓冲期。</li><li>会员等级在用户头像旁展示专属标识，满足用户的身份认同感。</li></ul><p>会员权益设计：</p><p>权益分为三类——价格权益、服务权益、专属权益。</p><p>价格权益：折扣、专属价、优惠券包。价格权益是用户最直接感知的，但也是成本最高的。折扣比例要经过财务测算，确保不会亏本。</p><p>服务权益：免运费、优先发货、专属客服、免费退换货。服务权益成本低但感知强，优先发货对高频用户特别有价值。</p><p>专属权益：生日礼包、新品优先购、线下活动邀请。专属权益是制造差异化的手段，让高等级会员有&quot;被特殊对待&quot;的体验。</p><p>积分体系设计：</p><p>积分是会员体系里的&quot;微型货币&quot;，让用户每次消费都有额外获得感。</p><table tabindex="0"><thead><tr><th>积分规则</th><th>说明</th></tr></thead><tbody><tr><td>获取规则</td><td>消费1元=1积分，评价1次=5积分，签到1次=2积分</td></tr><tr><td>消耗规则</td><td>100积分=1元抵扣，积分抵扣不超过订单金额的30%</td></tr><tr><td>过期规则</td><td>积分自然年有效，次年12月31日清零</td></tr><tr><td>获取上限</td><td>每日获取上限500积分，防刷积分</td></tr></tbody></table><p>积分商城设计：</p><ul><li>积分兑换优惠券：100积分兑换5元无门槛券，是最常用的兑换方式。</li><li>积分兑换实物：提供低价值但实用的商品（纸巾、垃圾袋等），让积分有&quot;真金白银&quot;的感觉。</li><li>积分+现金：高价值商品采用&quot;积分+现金&quot;模式，降低积分消耗速度。</li><li>积分抽奖：100积分抽一次，奖品包括大额券、实物、积分翻倍等，增加趣味性。</li></ul><h2 id="_10-2-电商产品设计实战" tabindex="-1">10.2 电商产品设计实战 <a class="header-anchor" href="#_10-2-电商产品设计实战" aria-label="Permalink to “10.2 电商产品设计实战”">​</a></h2><h3 id="_10-2-1-商品详情页设计" tabindex="-1">10.2.1 商品详情页设计 <a class="header-anchor" href="#_10-2-1-商品详情页设计" aria-label="Permalink to “10.2.1 商品详情页设计”">​</a></h3><p>商品详情页是电商产品转化率最高的页面。设计要点：</p><p><strong>信息层级</strong></p><p>第一屏：主图+价格+核心卖点。用户要不要继续看，第一屏决定。</p><p>第二屏：规格选择。颜色、尺寸、容量等规格选择。</p><p>第三屏：商品详情。图文详情、参数表、品牌故事。</p><p>第四屏：评价区。用户评价、问答、晒图。</p><p><strong>交互设计要点</strong></p><ul><li>规格选择要有&quot;库存提示&quot;：选了某个规格后，如果库存不足要提示</li><li>价格和库存要实时更新：切换规格后，价格和库存要立即变化</li><li>加入购物车要有&quot;成功反馈&quot;：加购成功后要有视觉反馈（如小球飞入购物车动画）</li></ul><p><strong>详情页转化率优化</strong></p><p>商品详情页的转化率直接影响GMV。行业平均详情页转化率在2%-5%之间，Top电商能到8%-12%。每一个百分点的提升，都是真金白银。</p><p>首屏优化：</p><p>首屏是用户的第一印象，决定了用户是否继续往下看。首屏的加载速度和信息密度是两个核心优化方向。</p><ul><li>首屏加载速度：首屏内容加载时间控制在1.5秒以内。图片采用WebP格式+懒加载，详情页大图按需加载。数据表明，加载时间每增加1秒，跳出率增加20%。</li><li>主图设计：第一张主图要包含商品主体+核心卖点文字，不要纯白底图。用户在搜索结果页已经看过白底图了，详情页第一张要给更多信息。</li><li>价格展示：价格字号是页面最大字号，不低于24px。划线价与实际价的对比要醒目，让用户一眼看到&quot;省了多少&quot;。</li><li>核心卖点提炼：价格下方用3-5个标签展示核心卖点（如&quot;旗舰芯片&quot;&quot;1亿像素&quot;&quot;快充66W&quot;），用户扫一眼就能判断商品是否符合需求。</li><li>行动按钮：底部固定&quot;加入购物车&quot;和&quot;立即购买&quot;按钮，用户任何时候想买都能直接操作，不需要滚回顶部。</li></ul><p>信任感建设：</p><p>电商购物用户最大的心理障碍是&quot;看不到实物&quot;，信任感建设是打消用户疑虑的关键。</p><ul><li>评价体系优化：默认展示&quot;有图评价&quot;和&quot;追评&quot;，这两类评价的可信度最高。差评不隐藏但要排后，让用户觉得评价是真实的。</li><li>服务承诺标签：在价格下方展示&quot;7天无理由退换&quot;&quot;正品保障&quot;&quot;极速退款&quot;等标签，每个标签可点击查看详细说明。</li><li>品牌授权信息：品牌商品展示&quot;品牌授权&quot;标识，点击可查看授权书。非品牌商品展示&quot;平台验真&quot;标识。</li><li>销量与口碑数据：展示&quot;近30天售出X件&quot;&quot;好评率98%&quot;等数据，数字比文字更有说服力。</li><li>视频展示：商品视频的观看完成率是图片浏览的3倍，能显著提升信任感。每个商品详情页至少配备1个主视频。</li><li>买家秀模块：展示真实用户的晒图和评价，比商家精修图更有信任感。支持&quot;查看相似穿搭&quot;等互动功能。</li></ul><p>紧迫感设计：</p><p>紧迫感是促使用户&quot;现在就买&quot;而非&quot;再看看&quot;的心理触发器。</p><ul><li>库存紧张提示：库存低于10件时展示&quot;仅剩X件&quot;，低于3件时展示&quot;即将售罄&quot;。但库存提示必须真实，虚假提示被用户识破后信任崩塌。</li><li>限时优惠倒计时：活动商品展示倒计时（如&quot;优惠还剩2小时13分&quot;），倒计时消失后价格恢复原价。倒计时要有声音或动画效果增强感知。</li><li>累计购买人数滚动：实时展示&quot;最近1小时X人下单&quot;，利用从众心理促单。</li><li>加购提醒：展示&quot;X人正在浏览此商品&quot;&quot;X人已加入购物车&quot;，制造竞争感。</li><li>恢复原价预告：促销价旁边展示&quot;X日后恢复原价¥XXX&quot;，让用户明确知道现在买更便宜。</li></ul><h3 id="_10-2-2-订单系统设计" tabindex="-1">10.2.2 订单系统设计 <a class="header-anchor" href="#_10-2-2-订单系统设计" aria-label="Permalink to “10.2.2 订单系统设计”">​</a></h3><p><strong>订单状态机</strong></p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>[待付款] --付款成功--&gt; [待发货] --商家发货--&gt; [待收货] --确认收货--&gt; [已完成]</span></span>
<span class="line"><span>    ↑                       |                      |</span></span>
<span class="line"><span>    └──取消/超时未付────────┴──申请退款─────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><strong>订单系统核心表设计</strong></p><table tabindex="0"><thead><tr><th>表名</th><th>核心字段</th><th>说明</th></tr></thead><tbody><tr><td>order</td><td>order_id, user_id, total_amount, status</td><td>订单主表</td></tr><tr><td>order_item</td><td>order_id, sku_id, quantity, price</td><td>订单商品表</td></tr><tr><td>order_payment</td><td>order_id, payment_method, payment_amount</td><td>支付记录表</td></tr><tr><td>order_logistics</td><td>order_id, logistics_company, tracking_no</td><td>物流信息表</td></tr></tbody></table><h3 id="_10-2-3-支付与结算设计" tabindex="-1">10.2.3 支付与结算设计 <a class="header-anchor" href="#_10-2-3-支付与结算设计" aria-label="Permalink to “10.2.3 支付与结算设计”">​</a></h3><p><strong>支付流程</strong></p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>确认订单 → 选择支付方式 → 调用支付接口 → 用户完成支付 → </span></span>
<span class="line"><span>支付回调 → 更新订单状态 → 跳转结果页</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong>支付方式选择</strong></p><table tabindex="0"><thead><tr><th>支付方式</th><th>适用场景</th><th>产品设计要点</th></tr></thead><tbody><tr><td>微信支付</td><td>全场景</td><td>小程序内只能用微信支付</td></tr><tr><td>支付宝</td><td>全场景</td><td>Web/App都支持</td></tr><tr><td>银行卡</td><td>大额支付</td><td>需要银行卡绑定和验证</td></tr><tr><td>余额支付</td><td>平台内支付</td><td>需要先充值</td></tr><tr><td>货到付款</td><td>下沉市场</td><td>线下收款，平台担保</td></tr></tbody></table><p><strong>支付安全设计</strong></p><p>支付安全是电商产品的生命线。一次支付安全事故，损失的不仅是钱，更是用户信任。信任崩塌只需要一次，重建可能需要一辈子。</p><p>支付密码设计：</p><ul><li>免密额度：设置小额免密额度（默认1000元），低于该金额免输密码直接支付，兼顾安全和便捷。</li><li>密码输入方式：6位数字密码，支持键盘随机排列防偷窥，输入过程不显示具体数字只显示圆点。</li><li>生物识别替代：支持指纹和面容ID替代密码输入，iOS设备优先推荐Face ID，Android设备优先推荐指纹。</li><li>密码错误处理：连续错误5次锁定30分钟，锁定期间不可支付。锁定前3次提示&quot;密码错误，还剩X次机会&quot;。</li><li>密码修改：修改支付密码需要验证短信验证码+原支付密码，双重验证确保安全。</li></ul><p>风控规则设计：</p><p>风控系统是支付安全的守门员。它要在用户无感知的情况下，识别并拦截异常交易。</p><table tabindex="0"><thead><tr><th>风控维度</th><th>风控规则</th><th>触发动作</th></tr></thead><tbody><tr><td>设备维度</td><td>同一设备1小时内支付超过5次</td><td>短信验证+人脸识别</td></tr><tr><td>账户维度</td><td>新注册账户首日支付超过500元</td><td>限制单日支付额度</td></tr><tr><td>金额维度</td><td>单笔支付超过5000元</td><td>短信验证+人工审核</td></tr><tr><td>频率维度</td><td>同一账户1分钟内发起3次支付</td><td>冻结支付30分钟</td></tr><tr><td>地域维度</td><td>支付IP与常用IP地域不一致</td><td>短信验证+安全提示</td></tr><tr><td>行为维度</td><td>支付前浏览时间低于3秒</td><td>弹窗确认&quot;是否确认支付&quot;</td></tr></tbody></table><p>风控规则的设计原则：</p><ul><li>规则要可配置：运营可以在后台调整每条规则的阈值和触发动作，不需要开发介入。</li><li>误杀率控制：风控规则的误杀率控制在0.5%以内，每拦截一笔正常交易都是对用户体验的伤害。</li><li>分级处理：不是所有风控触发都要拦截，低风险弹确认，中风险要短信验证，高风险才冻结。</li><li>实时更新：风控规则要根据最新的欺诈模式实时更新，每月至少迭代一次规则库。</li></ul><p>异常订单处理：</p><p>异常订单是支付环节的灰色地带——可能是欺诈，也可能是用户误操作。处理不好，要么让坏人跑了，要么让好人伤了。</p><table tabindex="0"><thead><tr><th>异常类型</th><th>识别方式</th><th>处理方案</th></tr></thead><tbody><tr><td>重复支付</td><td>同一订单两次支付成功</td><td>自动退款其中一笔，通知用户</td></tr><tr><td>支付超时</td><td>订单支付时间超过30分钟</td><td>自动取消订单，释放库存</td></tr><tr><td>金额异常</td><td>实付金额与订单金额不符</td><td>暂停订单，人工审核</td></tr><tr><td>拆单刷券</td><td>同一用户短时间多笔小额订单</td><td>合并计算优惠，追回差额</td></tr><tr><td>疑似盗刷</td><td>新设备+大额+非常用收货地址</td><td>冻结订单，电话核实</td></tr></tbody></table><p>异常订单处理流程：</p><ul><li>自动处理：重复支付、支付超时等明确场景由系统自动处理，不需要人工介入。</li><li>半自动处理：金额异常等需确认的场景，系统自动标记并生成工单，客服在2小时内处理。</li><li>人工处理：疑似盗刷等高风险场景，冻结订单后由风控专员电话核实用户本人，核实通过后解冻。</li><li>用户通知：所有异常订单处理后，通过站内信和短信通知用户处理结果和原因。</li><li>申诉通道：用户对处理结果不满意时，可提交申诉，申诉工单48小时内响应。</li></ul><h3 id="_10-2-4-电商数据指标体系" tabindex="-1">10.2.4 电商数据指标体系 <a class="header-anchor" href="#_10-2-4-电商数据指标体系" aria-label="Permalink to “10.2.4 电商数据指标体系”">​</a></h3><p><strong>电商核心指标</strong></p><table tabindex="0"><thead><tr><th>指标</th><th>定义</th><th>计算公式</th></tr></thead><tbody><tr><td>GMV</td><td>成交总额</td><td>所有订单金额之和（含未支付）</td></tr><tr><td>转化率</td><td>访客到买家的比例</td><td>下单用户数 / 访客数</td></tr><tr><td>客单价</td><td>平均每个订单的金额</td><td>GMV / 订单数</td></tr><tr><td>复购率</td><td>重复购买用户比例</td><td>复购用户数 / 总购买用户数</td></tr><tr><td>退款率</td><td>退款订单比例</td><td>退款订单数 / 总订单数</td></tr></tbody></table><p><strong>数据看板设计</strong></p><p>运营需要看的数据看板：</p><ul><li>实时GMV（按小时更新）</li><li>转化率漏斗（浏览→加购→下单→支付）</li><li>商品销量排行（按日/周/月）</li><li>用户复购分析（按用户分层）</li><li>退款原因分析（按商品/原因分类）</li></ul><p>本章小结：电商产品的核心是三个体系——商品体系（SPU/SKU/类目）、交易体系（订单/支付/物流）、营销体系（优惠券/秒杀/拼团）。掌握了这三个体系，电商产品的设计就有了骨架。</p><table tabindex="0"><thead><tr><th>本章核心知识点</th><th>一句话总结</th></tr></thead><tbody><tr><td>SPU vs SKU</td><td>SPU是标准化产品，SKU是库存单位</td></tr><tr><td>商品信息结构</td><td>SPU层+SKU层+销售层+展示层</td></tr><tr><td>交易流程</td><td>浏览→加购→下单→支付→发货→收货→评价</td></tr><tr><td>优惠券系统</td><td>创建→发放→使用，三模块闭环</td></tr><tr><td>订单状态机</td><td>待付款→待发货→待收货→已完成，含退款分支</td></tr><tr><td>电商核心指标</td><td>GMV、转化率、客单价、复购率、退款率</td></tr><tr><td>商品搜索</td><td>搜索框交互+搜索建议+排序策略+筛选器，四层设计</td></tr><tr><td>购物车</td><td>页面结构+数量修改+优惠券选择+凑单引导</td></tr><tr><td>退款流程</td><td>退款类型+状态机+凭证+金额计算+极速退款</td></tr><tr><td>满减活动</td><td>门槛设计+阶梯满减+防坑机制+前端展示</td></tr><tr><td>会员体系</td><td>等级+权益+积分，三层架构驱动复购</td></tr><tr><td>详情页优化</td><td>首屏优化+信任感建设+紧迫感设计，三管齐下</td></tr><tr><td>支付安全</td><td>支付密码+风控规则+异常订单，三层防线</td></tr></tbody></table><p>觉得有用？收藏起来，下次做电商产品直接照抄框架。</p><p>你做过电商产品吗？评论区分享你的经验。</p><p>关注怕浪猫，下期我们讲&quot;后台类产品设计&quot;——B端产品的设计思路，怕浪猫帮你拆解。</p><p>系列进度 10/16</p><p><strong>下章预告：</strong> 第11章，B端产品和C端产品完全不同。用户不是消费者，而是企业员工。需求不是&quot;我想要&quot;，而是&quot;我工作需要&quot;。下一章，怕浪猫带你理解B端产品的设计逻辑。</p>`,170)])])}const q=d(r,[["render",s]]);export{b as __pageData,q as default};
